// Composant principal avec les providers
const App = () => {
  const [isConfigured, setIsConfigured] = useState(false);
  const [isChecking, setIsChecking] = useState(true);

  useEffect(() => {
    const checkConfiguration = () => {
      try {
        console.log('[APP] Vérification des variables d\'environnement...');

        // Vérification simple des variables d'environnement
        const hasSupabaseUrl = !!process.env.REACT_APP_SUPABASE_URL;
        const hasSupabaseKey = !!process.env.REACT_APP_SUPABASE_ANON_KEY;
        const hasBackendUrl = !!process.env.REACT_APP_BACKEND_URL;

        console.log('[APP] Variables d\'environnement:', {
          hasSupabaseUrl,
          hasSupabaseKey,
          hasBackendUrl,
          url: process.env.REACT_APP_SUPABASE_URL ? 'Définie' : 'Manquante',
          key: process.env.REACT_APP_SUPABASE_ANON_KEY ? 'Définie' : 'Manquante',
          backend: process.env.REACT_APP_BACKEND_URL ? 'Définie' : 'Manquante'
        });

        // Configuration OK si toutes les variables sont présentes
        const configured = hasSupabaseUrl && hasSupabaseKey && hasBackendUrl;
        setIsConfigured(configured);

        if (configured) {
          console.log('[APP] ✅ Configuration détectée, démarrage de l\'application');
        } else {
          console.log('[APP] ❌ Configuration manquante, affichage de la page de configuration');
        }
      } catch (error) {
        console.error('[APP] Erreur lors de la vérification de la configuration:', error);
        setIsConfigured(false);
      } finally {
        setIsChecking(false);
      }
    };

    // Vérification immédiate sans délai
    checkConfiguration();
  }, []);

  // Afficher un loader pendant la vérification
  if (isChecking) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 flex items-center justify-center">
        <div className="text-center">
          <div className="w-16 h-16 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-gray-600">Vérification de la configuration...</p>
        </div>
      </div>
    );
  }

  if (!isConfigured) {
    return <ConfigurationPage />;
  }

  return (
    <AuthProvider>
      <NotificationProvider>
        <AppContent />
        <Toaster position="top-right" />
      </NotificationProvider>
    </AuthProvider>
  );
};

export default App;
